import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"圆明园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan.md","filePath":"landmarks/yuanmingyuan.md","lastUpdated":null}'),l={name:"landmarks/yuanmingyuan.md"};function n(i,t,s,h,d,u){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="圆明园" tabindex="-1">圆明园 <a class="header-anchor" href="#圆明园" aria-label="Permalink to &quot;圆明园&quot;">​</a></h1><blockquote><p>&quot;万园之园，东方凡尔赛，如今只剩断壁残垣。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>圆明园是清代著名的皇家园林，由圆明园、长春园、绮春园三园组成，统称&quot;圆明三园&quot;，占地350多公顷，其中水面面积约140公顷。圆明园以其宏大的地域规模、杰出的营造技艺、精美的建筑景群、丰富的文化收藏和博大精深的民族文化内涵而享誉于世，被誉为&quot;一切造园艺术的典范&quot;和&quot;万园之园&quot;。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">7:00-19:00（旺季），7:00-17:30（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">大门门票10元，西洋楼遗址15元，全景模型展10元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线圆明园站</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">圆明园遗址公园官网预约</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建与发展" tabindex="-1">始建与发展 <a class="header-anchor" href="#始建与发展" aria-label="Permalink to &quot;始建与发展&quot;">​</a></h3><p>圆明园始建于康熙四十八年（1709年），最初是康熙帝赐给皇四子胤禛（即后来的雍正帝）的花园。雍正即位后大规模扩建，乾隆时期达到鼎盛，历经康雍乾嘉道咸六朝150余年的营造。</p><h3 id="辉煌时期" tabindex="-1">辉煌时期 <a class="header-anchor" href="#辉煌时期" aria-label="Permalink to &quot;辉煌时期&quot;">​</a></h3><p>鼎盛时期的圆明园，拥有景点150余处，建筑面积20余万平方米。园中仿建了多处江南名园胜景，如杭州西湖十景、苏州狮子林等，还建有西洋楼等西式建筑群。</p><h3 id="浩劫与毁灭" tabindex="-1">浩劫与毁灭 <a class="header-anchor" href="#浩劫与毁灭" aria-label="Permalink to &quot;浩劫与毁灭&quot;">​</a></h3><p>咸丰十年（1860年）10月，英法联军攻入北京，对圆明园进行了疯狂洗劫，随后纵火焚烧，大火三天三夜不熄。1900年八国联军再次洗劫，民国时期的石劫、木劫、土劫使这座园林彻底化为废墟。</p><h3 id="遗址公园" tabindex="-1">遗址公园 <a class="header-anchor" href="#遗址公园" aria-label="Permalink to &quot;遗址公园&quot;">​</a></h3><p>新中国成立后，圆明园遗址得到有效保护。1976年成立圆明园管理处，1988年对外开放，成为全国重点文物保护单位和爱国主义教育基地。</p><h2 id="园林布局" tabindex="-1">园林布局 <a class="header-anchor" href="#园林布局" aria-label="Permalink to &quot;园林布局&quot;">​</a></h2><h3 id="圆明园-主园" tabindex="-1">圆明园（主园） <a class="header-anchor" href="#圆明园-主园" aria-label="Permalink to &quot;圆明园（主园）&quot;">​</a></h3><p>圆明园是主园，占地最大，以水面为主，仿江南园林布局，有&quot;四十景&quot;之称。主要景点包括：</p><ul><li><strong>正大光明殿</strong>：皇帝在园中处理政务的地方</li><li><strong>九洲清晏</strong>：皇帝的寝宫区</li><li><strong>勤政亲贤</strong>：皇帝日常办公之所</li><li><strong>镂月开云</strong>：牡丹台，康熙、乾隆、嘉庆三代皇帝在此共赏牡丹</li><li><strong>天然图画</strong>：仿西湖&quot;平湖秋月&quot;而建</li></ul><h3 id="长春园" tabindex="-1">长春园 <a class="header-anchor" href="#长春园" aria-label="Permalink to &quot;长春园&quot;">​</a></h3><p>长春园以西洋楼建筑群著称，是园中唯一的西式景区。</p><h4 id="西洋楼遗址" tabindex="-1">西洋楼遗址 <a class="header-anchor" href="#西洋楼遗址" aria-label="Permalink to &quot;西洋楼遗址&quot;">​</a></h4><p>西洋楼占地约6万平方米，由谐奇趣、蓄水楼、万花阵、养雀笼、方外观、海晏堂、大水法、观水法、远瀛观等十余座西式建筑和园林组成。</p><p><strong>海晏堂</strong>：西洋楼中最大的建筑，楼前有十二生肖兽首人身像喷泉，每昼夜十二时辰依次喷水，正午时十二生肖同时喷水，蔚为壮观。</p><p><strong>大水法</strong>：欧式喷泉，主楼前有椭圆形喷水池，池中有铜鹿、铜狗等喷水装置。残存的大理石柱至今矗立，成为圆明园的象征。</p><h3 id="绮春园" tabindex="-1">绮春园 <a class="header-anchor" href="#绮春园" aria-label="Permalink to &quot;绮春园&quot;">​</a></h3><p>绮春园原是若干私园，乾隆后期并入圆明园，嘉庆年间大规模扩建。主要景点有：</p><ul><li><strong>正觉寺</strong>：清代皇室喇嘛庙</li><li><strong>鉴碧亭</strong>：临水而建，是赏荷佳处</li><li><strong>涵秋馆</strong>：秋季赏景之所</li></ul><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="十二生肖兽首" tabindex="-1">十二生肖兽首 <a class="header-anchor" href="#十二生肖兽首" aria-label="Permalink to &quot;十二生肖兽首&quot;">​</a></h3><p>海晏堂前的十二生肖兽首人身铜像，由意大利传教士郎世宁设计，法国人蒋友仁监修，是中西合璧的艺术精品。1860年英法联军劫掠后，兽首流散世界各地。</p><p>目前已有牛首、猴首、虎首、猪首、马首、鼠首、兔首回归祖国，龙首据说在台湾，蛇首、羊首、鸡首、狗首至今下落不明。</p><h3 id="文源阁与《四库全书》" tabindex="-1">文源阁与《四库全书》 <a class="header-anchor" href="#文源阁与《四库全书》" aria-label="Permalink to &quot;文源阁与《四库全书》&quot;">​</a></h3><p>文源阁是圆明园中收藏《四库全书》的处所。《四库全书》是清代乾隆年间编纂的大型丛书，收录书籍3503种，79337卷，是中国历史上最大的一部丛书。文源阁于1860年被焚毁，《四库全书》部分被劫掠，部分被焚毁。</p><h3 id="咸丰帝与圆明园" tabindex="-1">咸丰帝与圆明园 <a class="header-anchor" href="#咸丰帝与圆明园" aria-label="Permalink to &quot;咸丰帝与圆明园&quot;">​</a></h3><p>咸丰十年（1860年），英法联军逼近北京，咸丰帝携慈禧等人逃往热河避难。临行前，咸丰帝在圆明园度过了最后的时光。一年后，咸丰帝在热河病逝，终年仅30岁。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约3小时）</strong>：</p><p>南门 → 十二生肖兽首展 → 绮春园 → 三园交界 → 长春园 → 西洋楼遗址（谐奇趣→万花阵→养雀笼→方外观→海晏堂→大水法→观水法→线法山→线法墙）→ 东门</p><p><strong>深度路线（约5-6小时）</strong>：</p><p>南门 → 正觉寺 → 绮春园 → 三园交界 → 圆明园（九州景区→福海景区）→ 长春园 → 西洋楼遗址 → 全景模型 → 东门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>联票建议</strong>：一定要购买含西洋楼遗址的联票，否则看不到大水法等标志性景观</li><li><strong>游览车</strong>：园区较大，可乘电瓶车（10-15元/站）节省体力</li><li><strong>讲解服务</strong>：建议请人工讲解或租用语音导览，了解历史背景更有意义</li><li><strong>最佳时间</strong>：春秋两季，尤其是秋天银杏黄时</li><li><strong>心态准备</strong>：圆明园是一个&quot;看废墟&quot;的地方，带着历史敬畏心来参观</li></ol><h2 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h2><p>圆明园的毁灭是中华民族的奇耻大辱，也是人类文明史上的一场浩劫。它不仅是一座园林的毁灭，更是中华文明遭受重创的象征。</p><p>如今的圆明园遗址公园，以残垣断壁向世人诉说着那段屈辱的历史，成为爱国主义教育的重要基地。正如法国作家雨果所说：</p><blockquote><p>&quot;有一天，两个强盗闯进了圆明园。一个抢劫，一个放火……在历史面前，这两个强盗一个叫法兰西，一个叫英吉利。&quot;</p></blockquote><hr><p><strong>📍 地址</strong>：北京市海淀区清华西路28号 <strong>📞 电话</strong>：010-62543673 <strong>🌐 官网</strong>：<a href="http://www.yuanmingyuanpark.com" target="_blank" rel="noreferrer">www.yuanmingyuanpark.com</a></p>',50)])])}const q=a(l,[["render",n]]);export{p as __pageData,q as default};
